CREATE TABLE `Pembenihan` (
    `id`	INT(11) NOT NULL PRIMARY,
    `TAHUN`	INT(4) DEFAULT NULL,
    `PROVINSI`	VARCHAR(512) DEFAULT NULL,
    `JENIS_PEMBENIHAN`	VARCHAR(512) DEFAULT NULL,
    `KAB_KOTA`	VARCHAR(512) DEFAULT NULL,
    `KELOMPOK_IKAN`	VARCHAR(512) DEFAULT NULL,
    `VOLUME`	INT DEFAULT NULL
);

